local Players = game:GetService("Players")
local RunService = game:GetService("RunService")

local player = Players.LocalPlayer
local house = Instance.new("Model")
house.Name = "GeneratedTestHouse"
house.Parent = workspace

local HOUSE_OFFSET = Vector3.new(5000, 0, 5000)

local function makePiece(d)
	local part = Instance.new(d[1])
	part.Name = d[2]
	part.Size = Vector3.new(table.unpack(d[3]))
	part.CFrame = CFrame.new(table.unpack(d[4])) + HOUSE_OFFSET
	part.Color = Color3.fromRGB(table.unpack(d[5]))
	part.Material = d[6]
	part.Transparency = d[7]
	part.Reflectance = d[8]
	part.Anchored, part.CanCollide, part.CanTouch, part.CanQuery, part.CastShadow = true, true, true, true, true
	part.Parent = house
	return part
end

