local houseCF, houseSize = house:GetBoundingBox()
local HOUSE_CENTER = houseCF.Position
local SPAWN_CFRAME = CFrame.new(HOUSE_CENTER + Vector3.new(0, houseSize.Y / 2 + 20, 0))
local TELEPORT_THRESHOLD = math.max(houseSize.X, houseSize.Z) * 2
local COOLDOWN = 1
local lastSafeTime = 0
local charConn, antiTpConn

local function teleportCharacter(char)
	local hrp = char:WaitForChild("HumanoidRootPart")
	hrp.CFrame = SPAWN_CFRAME
end

local function setupAntiTeleport(char)
	if antiTpConn then antiTpConn:Disconnect() end
	local hrp = char:WaitForChild("HumanoidRootPart")
	antiTpConn = RunService.Heartbeat:Connect(function()
		if not house.Parent or not hrp.Parent then return end
		if (hrp.Position - HOUSE_CENTER).Magnitude > TELEPORT_THRESHOLD and os.clock() - lastSafeTime > COOLDOWN then
			lastSafeTime = os.clock()
			hrp.CFrame = SPAWN_CFRAME
		end
	end)
end

if player.Character then
	teleportCharacter(player.Character)
	setupAntiTeleport(player.Character)
end

charConn = player.CharacterAdded:Connect(function(char)
	teleportCharacter(char)
	setupAntiTeleport(char)
end)

local function createButton()
	local character = player.Character or player.CharacterAdded:Wait()
	local hrp = character:WaitForChild("HumanoidRootPart")
	local button = Instance.new("Part")
	button.Size = Vector3.new(2, .5, 1)
	button.Anchored = true
	button.Color = Color3.fromRGB(255, 0, 0)
	button.Name = "DeletePlatformButton"
	button.CFrame = hrp.CFrame * CFrame.new(0, -15, -5)
	button.Parent = workspace

	local click = Instance.new("ClickDetector", button)
	local billboard = Instance.new("BillboardGui")
	billboard.Size = UDim2.new(0, 200, 0, 50)
	billboard.StudsOffset = Vector3.new(0, 4, 0)
	billboard.AlwaysOnTop = true
	billboard.Parent = button

	local text = Instance.new("TextLabel")
	text.Size = UDim2.new(1, 0, 1, 0)
	text.BackgroundTransparency = 1
	text.Text = "DELETE PLATFORM"
	text.TextScaled = true
	text.TextColor3 = Color3.new(1, 1, 1)
	text.Parent = billboard

	local cleaned = false
	local function cleanup()
		if cleaned then return end
		cleaned = true
		if house then house:Destroy() end
		if button then button:Destroy() end
		if charConn then charConn:Disconnect(); charConn = nil end
		if antiTpConn then antiTpConn:Disconnect(); antiTpConn = nil end
	end

	click.MouseClick:Connect(cleanup)
end

createButton()
